if (! function_exists('data_linear_regression')) {
    function data_linear_regression($x, $y, $predict_x = null)
    {
        if (count($x) !== count($y) || count($x) < 2) {
            return json_encode(['error' => 'x and y must have same length with at least 2 points']);
        }
        $n = count($x);
        $sumX = array_sum($x); $sumY = array_sum($y);
        $sumX2 = 0; $sumY2 = 0; $sumXY = 0;
        for ($i = 0; $i < $n; $i++) {
            $sumX2 += $x[$i] * $x[$i];
            $sumY2 += $y[$i] * $y[$i];
            $sumXY += $x[$i] * $y[$i];
        }
        $meanX = $sumX / $n; $meanY = $sumY / $n;
        $slope = ($n * $sumXY - $sumX * $sumY) / ($n * $sumX2 - $sumX * $sumX);
        $intercept = $meanY - $slope * $meanX;
        // Pearson r
        $num = $n * $sumXY - $sumX * $sumY;
        $den = sqrt(($n * $sumX2 - $sumX * $sumX) * ($n * $sumY2 - $sumY * $sumY));
        $r = $den != 0 ? $num / $den : 0;
        $r2 = $r * $r;
        // Standard error of estimate
        $residuals = [];
        $sse = 0;
        for ($i = 0; $i < $n; $i++) {
            $pred = $slope * $x[$i] + $intercept;
            $res = $y[$i] - $pred;
            $residuals[] = $res;
            $sse += $res * $res;
        }
        $se = $n > 2 ? sqrt($sse / ($n - 2)) : 0;
        // Predictions
        $predictions = [];
        if (!empty($predict_x)) {
            foreach ($predict_x as $px) {
                $predictions[] = ['x' => $px, 'y_predicted' => round($slope * $px + $intercept, 6)];
            }
        }
        // Fitted values
        $fitted = [];
        for ($i = 0; $i < $n; $i++) {
            $fitted[] = round($slope * $x[$i] + $intercept, 6);
        }
        return json_encode([
            'n' => $n,
            'slope' => round($slope, 6),
            'intercept' => round($intercept, 6),
            'r' => round($r, 6),
            'r_squared' => round($r2, 6),
            'std_error' => round($se, 6),
            'mean_x' => round($meanX, 4),
            'mean_y' => round($meanY, 4),
            'equation' => 'y = ' . round($slope, 4) . 'x + ' . round($intercept, 4),
